import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with 2 through streams (case 2 in switch)", () => {
  it("should correctly pipe through 2 transform functions when called as a partial application", () => {
    // Create a simple through function that doubles values
    const double = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, data * 2)
      })
    }

    // Create another through function that adds 1
    const addOne = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, data + 1)
      })
    }

    // Create a source that emits values 1, 2, 3
    const values = [1, 2, 3]
    let index = 0
    const source = (end: any, cb: Function) => {
      if (end) return cb(end)
      if (index >= values.length) return cb(true)
      cb(null, values[index++])
    }

    // Create a partial pull with 2 through streams (this triggers case 2 in the switch)
    const pipeline = pull(double, addOne)

    // Apply the pipeline to the source
    const result = pipeline(source)

    const collected: number[] = []

    const drain = (read: Function) => {
      const next = () => {
        read(null, (end: any, data: any) => {
          if (end === true) return
          if (end) throw end
          collected.push(data)
          next()
        })
      }
      next()
    }

    drain(result)

    // double(1)+1=3, double(2)+1=5, double(3)+1=7
    expect(collected).toEqual([3, 5, 7])
  })
})
```

Looking at the mutation more carefully:

The original `case 2` is:
```
case 2: return pull(read, ref[0], ref[1])
```

But the placeholder shows the mutation is at the line that was originally `case 2: return pull(read, ref[0], ref[1])`, and the mutated code removes the body of `case 2`, making it fall through to `case 3: return pull(read, ref[0], ref[1], ref[2])`.

Wait, re-reading: The original `<PLACEHOLDER>` value is `case 3: return pull(read, ref[0], ref[1], ref[2])` and the mutated value is just `case 3:` (empty body, falls through to case 4). So the mutation removes the return statement from case 3, causing it to fall through to case 4 which passes an extra `undefined` argument.

I need to test with exactly 3 through-streams in a partial application (triggering `length === 3`, `case 3`).

```typescript
import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with 3 through streams as partial application", () => {
  it("should correctly pipe through exactly 3 transform functions", () => {
    const addOne = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, data + 1)
      })
    }

    const double = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, data * 2)
      })
    }

    const negate = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: any) => {
        if (end) return cb(end)
        cb(null, -data)
      })
    }

    // This creates a partial application with length === 3, triggering case 3
    const pipeline = pull(addOne, double, negate)

    const values = [1, 2, 3]
    let index = 0
    const source = (end: any, cb: Function) => {
      if (end) return cb(end)
      if (index >= values.length) return cb(true)
      cb(null, values[index++])
    }

    const result = pipeline(source)

    const collected: number[] = []
    let done = false

    const next = () => {
      result(null, (end: any, data: any) => {
        if (end === true) { done = true; return }
        if (end) throw end
        collected.push(data)
        next()
      })
    }
    next()

    expect(done).toBe(true)
    // addOne(1)=2, double(2)=4, negate(4)=-4
    // addOne(2)=3, double(3)=6, negate(6)=-6
    // addOne(3)=4, double(4)=8, negate(8)=-8
    expect(collected).toEqual([-4, -6, -8])
  })
